--
-- Name: fn_block_dangerous_cost_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fn_block_dangerous_cost_update() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Skip guard for intentional loss leaders (margin_floor set negative by hand)
  IF NEW.margin_floor < 0 THEN
    RETURN NEW;
  END IF;

  IF NEW.retail_price > 0 AND NEW.purchase_cost > NEW.retail_price THEN
       'cost ' || NEW.purchase_cost || 'p > retail ' || NEW.retail_price
         || 'p (ratio ' || ROUND(NEW.purchase_cost::numeric / NULLIF(NEW.retail_price,0), 1)
         || 'x) — likely per-case price stored as per-unit. '
         || 'Check units_per_case in purchase_invoice_items and case_size on the product.',
       true, 'trigger');
    RETURN NULL;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_block_dangerous_cost_update() OWNER TO postgres;

--
-- Name: fn_block_implausible_retail(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fn_block_implausible_retail() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_cat_median integer; v_hist_max integer; v_ceiling integer; v_anchors integer[] := '{}';
BEGIN
  IF current_setting('app.bypass_price_guard', true) = 'on' THEN RETURN NEW; END IF;
  SELECT round(percentile_cont(0.5) WITHIN GROUP (ORDER BY retail_price))::integer INTO v_cat_median
    FROM products WHERE category = NEW.category AND is_active AND retail_price > 0;
  SELECT max(new_price) INTO v_hist_max FROM price_history WHERE product_id = NEW.id AND price_type='retail';
  IF OLD.retail_price >= 20 THEN v_anchors := v_anchors || (OLD.retail_price * 3); END IF;
  IF v_hist_max >= 20 THEN v_anchors := v_anchors || (v_hist_max * 3); END IF;
  IF v_cat_median IS NOT NULL AND v_cat_median > 0 THEN v_anchors := v_anchors || (v_cat_median * 4); END IF;
  IF array_length(v_anchors,1) IS NULL THEN RETURN NEW; END IF;
  SELECT max(a) INTO v_ceiling FROM unnest(v_anchors) AS a;
  IF NEW.retail_price > v_ceiling THEN
    VALUES (NEW.id, NEW.name, OLD.retail_price, NEW.retail_price, v_ceiling,
      'Blocked retail £' || to_char(NEW.retail_price/100.0,'FM999990.00') || ' — exceeds plausible max £' || to_char(v_ceiling/100.0,'FM999990.00') || ' (was £' || to_char(OLD.retail_price/100.0,'FM999990.00') || '). Looks like a bad cost or multiplier. Use "Apply anyway" on /pricing to override.',
      true, 'retail_guard');
    RETURN NULL;
  END IF;
  RETURN NEW;
END; $$;


ALTER FUNCTION public.fn_block_implausible_retail() OWNER TO postgres;

--
-- Name: golem_stale_costs(text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.golem_stale_costs(supplier_filter text DEFAULT NULL::text, stale_days integer DEFAULT 14, min_appearances integer DEFAULT 3) RETURNS TABLE(id uuid, name text, last_invoice_date date, days_since integer)
    LANGUAGE sql STABLE
    AS $$
  SELECT
    p.id,
    p.name,
    MAX(pi.invoice_date)::date                                  AS last_invoice_date,
    (CURRENT_DATE - MAX(pi.invoice_date)::date)::int            AS days_since
  FROM products p
  JOIN purchase_invoice_items pii ON pii.product_id = p.id
  JOIN purchase_invoices pi       ON pi.id = pii.invoice_id
  WHERE p.is_active     = true
    AND p.purchase_cost > 0
    AND (supplier_filter IS NULL OR pi.supplier_name ILIKE '%' || supplier_filter || '%')
  GROUP BY p.id, p.name
  HAVING COUNT(pii.id) >= min_appearances
     AND (CURRENT_DATE - MAX(pi.invoice_date)::date) > stale_days
  ORDER BY days_since DESC;
$$;


ALTER FUNCTION public.golem_stale_costs(supplier_filter text, stale_days integer, min_appearances integer) OWNER TO postgres;

