--
-- Name: mark_overdue_invoices(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.mark_overdue_invoices() RETURNS void
    LANGUAGE plpgsql
    AS $$
begin
  update wholesale_invoices
  set    payment_status = 'overdue'
  where  payment_status in ('unpaid', 'partial')
  and    due_date < current_date;
end;
$$;


ALTER FUNCTION public.mark_overdue_invoices() OWNER TO postgres;

--
-- Name: pay_wholesale_invoice_full(uuid, uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.pay_wholesale_invoice_full(p_invoice_id uuid, p_customer_id uuid, p_user_id uuid, p_notes text DEFAULT NULL::text) RETURNS integer
    LANGUAGE plpgsql
    AS $$
declare
  v_customer_id uuid;
  v_total       integer;
  v_paid        integer;
  v_status      invoice_payment_status;
  v_balance     integer;
begin
  select customer_id, total_amount, amount_paid, payment_status
    into v_customer_id, v_total, v_paid, v_status
  from   wholesale_invoices
  where  id = p_invoice_id
  for update;                       -- serialize concurrent callers

  if not found or v_customer_id is distinct from p_customer_id then
    raise exception 'invoice not found' using errcode = 'P0002';
  end if;

  if v_status = 'paid' then
    raise exception 'invoice already paid' using errcode = 'P0001';
  end if;

  v_balance := v_total - coalesce(v_paid, 0);
  if v_balance <= 0 then
    raise exception 'nothing to pay' using errcode = 'P0003';
  end if;

  values (p_invoice_id, v_customer_id, v_balance, current_date, 'other', null, p_notes, p_user_id);

  update wholesale_invoices
  set    amount_paid = coalesce(v_paid, 0) + v_balance,
         payment_status = 'paid'
  where  id = p_invoice_id;

  return v_balance;
end;
$$;


ALTER FUNCTION public.pay_wholesale_invoice_full(p_invoice_id uuid, p_customer_id uuid, p_user_id uuid, p_notes text) OWNER TO postgres;

--
-- Name: recompute_product_default_unit(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.recompute_product_default_unit() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  update products p
  set default_unit_type = m.unit_type
  from (
    select unit_type
    from wholesale_order_items
    where product_id = new.product_id
    group by unit_type
    order by count(*) desc, (unit_type = 'box') desc
    limit 1
  ) m
  where p.id = new.product_id;
  return new;
end;
$$;


ALTER FUNCTION public.recompute_product_default_unit() OWNER TO postgres;

--
-- Name: record_price_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.record_price_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  if new.retail_price <> old.retail_price then
    values (new.id, 'retail', old.retail_price, new.retail_price, 'auto');
  end if;

  if new.wholesale_price <> old.wholesale_price then
    values (new.id, 'wholesale', old.wholesale_price, new.wholesale_price, 'auto');
  end if;

  if new.purchase_cost <> old.purchase_cost then
    values (new.id, 'purchase', old.purchase_cost, new.purchase_cost, 'auto');
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.record_price_change() OWNER TO postgres;

--
-- Name: record_wholesale_payment(uuid, integer, date, public.payment_method, text, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.record_wholesale_payment(p_invoice_id uuid, p_amount integer, p_date date, p_method public.payment_method, p_reference text, p_notes text, p_user_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
  v_customer_id uuid;
  v_total       integer;
  v_paid        integer;
  v_new_paid    integer;
  v_status      invoice_payment_status;
begin
  select customer_id, total_amount, amount_paid
  into   v_customer_id, v_total, v_paid
  from   wholesale_invoices
  where  id = p_invoice_id
  for update;

  v_new_paid := v_paid + p_amount;

  if v_new_paid >= v_total then
    v_status := 'paid';
  elsif v_new_paid > 0 then
    v_status := 'partial';
  else
    v_status := 'unpaid';
  end if;

  values (p_invoice_id, v_customer_id, p_amount, p_date, p_method, p_reference, p_notes, p_user_id);

  update wholesale_invoices
  set    amount_paid = v_new_paid, payment_status = v_status
  where  id = p_invoice_id;
end;
$$;


ALTER FUNCTION public.record_wholesale_payment(p_invoice_id uuid, p_amount integer, p_date date, p_method public.payment_method, p_reference text, p_notes text, p_user_id uuid) OWNER TO postgres;

