--
-- Name: product_last_invoice; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.product_last_invoice WITH (security_invoker='on') AS
 SELECT DISTINCT ON (pii.product_id) pii.product_id,
    pii.unit_cost AS box_price_pence,
    pii.unit_type,
    pii.box_weight_kg,
    pii.units_per_case,
    pi.invoice_date
   FROM (public.purchase_invoice_items pii
     JOIN public.purchase_invoices pi ON ((pi.id = pii.invoice_id)))
  WHERE ((pii.is_matched = true) AND (pii.product_id IS NOT NULL))
  ORDER BY pii.product_id, pi.invoice_date DESC, pii.id DESC;


ALTER VIEW public.product_last_invoice OWNER TO postgres;

