    product_id uuid NOT NULL,
    month_number integer NOT NULL,
    avg_price_per_unit_pence integer NOT NULL,
    sample_count integer DEFAULT 0 NOT NULL,
    min_year integer,
    max_year integer,
    last_computed timestamp with time zone DEFAULT now() NOT NULL,
    unit_type text NOT NULL,
    CONSTRAINT product_seasonal_averages_month_number_check CHECK (((month_number >= 1) AND (month_number <= 12))),
    CONSTRAINT product_seasonal_averages_unit_type_check CHECK ((unit_type = ANY (ARRAY['weight'::text, 'count'::text])))
);


ALTER TABLE public.product_seasonal_averages OWNER TO postgres;

--
-- Name: product_supplier_last_price; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.product_supplier_last_price WITH (security_invoker='on') AS
 SELECT DISTINCT ON (pii.product_id, s.mapped_supplier) pii.product_id,
    s.mapped_supplier AS supplier_name,
    pii.unit_cost AS last_price_p,
    pi.invoice_date AS last_date
   FROM ((public.purchase_invoice_items pii
     JOIN public.purchase_invoices pi ON ((pi.id = pii.invoice_id)))
     CROSS JOIN LATERAL ( SELECT
                CASE
                    WHEN (pi.supplier_name ~~* '%total produce%'::text) THEN 'dole wholesale gateshead'::text
                    WHEN (pi.supplier_name ~~* '%dole%'::text) THEN 'dole wholesale gateshead'::text
                    WHEN (pi.supplier_name ~~* '%holland%'::text) THEN 'jr holland'::text
                    ELSE NULL::text
                END AS mapped_supplier) s)
  WHERE ((pii.product_id IS NOT NULL) AND (s.mapped_supplier IS NOT NULL))
  ORDER BY pii.product_id, s.mapped_supplier, pi.invoice_date DESC, pii.id DESC;


ALTER VIEW public.product_supplier_last_price OWNER TO postgres;

