    unit text NOT NULL,
    unit_price_pence integer NOT NULL,
    line_total_pence integer NOT NULL
);


ALTER TABLE public.till_transaction_items OWNER TO postgres;

--
-- Name: till_transactions; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.till_transactions (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    total_pence integer NOT NULL,
    payment_method text NOT NULL,
    cash_tendered_pence integer,
    change_pence integer,
    status text DEFAULT 'completed'::text NOT NULL,
    CONSTRAINT till_transactions_payment_method_check CHECK ((payment_method = ANY (ARRAY['cash'::text, 'card'::text, 'mixed'::text]))),
    CONSTRAINT till_transactions_status_check CHECK ((status = ANY (ARRAY['completed'::text, 'voided'::text])))
);


ALTER TABLE public.till_transactions OWNER TO postgres;

--
-- Name: user_profiles; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.user_profiles (
    id uuid NOT NULL,
    full_name text,
    role public.user_role DEFAULT 'cashier'::public.user_role NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.user_profiles OWNER TO postgres;

--
-- Name: waste_log; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.waste_log (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    product_id uuid NOT NULL,
    quantity numeric(10,3) NOT NULL,
    unit_cost integer NOT NULL,
    total_cost integer GENERATED ALWAYS AS (((quantity * (unit_cost)::numeric))::integer) STORED,
    reason public.waste_reason DEFAULT 'spoiled'::public.waste_reason NOT NULL,
    notes text,
    logged_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.waste_log OWNER TO postgres;

--
-- Name: wholesale_customers; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.wholesale_customers (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    name text NOT NULL,
    contact_name text,
    email text,
    phone text,
    address text,
    payment_terms integer DEFAULT 30 NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    portal_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    is_internal boolean DEFAULT false NOT NULL,
    notes text,
    account_number text,
    order_contacts text[]
);


ALTER TABLE public.wholesale_customers OWNER TO postgres;

--
-- Name: wholesale_invoice_items; Type: TABLE; Schema: public; Owner: postgres
--

