--
-- Name: users trg_auth_user_created; Type: TRIGGER; Schema: auth; Owner: supabase_auth_admin
--

CREATE TRIGGER trg_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();


--
-- Name: market_session_items set_market_session_items_updated_at; Type: TRIGGER; Schema: public; Owner: postgres
--

CREATE TRIGGER set_market_session_items_updated_at BEFORE UPDATE ON public.market_session_items FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();


--
-- Name: products trg_cost_safety_guard; Type: TRIGGER; Schema: public; Owner: postgres
--

CREATE TRIGGER trg_cost_safety_guard BEFORE UPDATE OF purchase_cost ON public.products FOR EACH ROW WHEN (((new.purchase_cost IS DISTINCT FROM old.purchase_cost) AND (new.purchase_cost IS NOT NULL))) EXECUTE FUNCTION public.fn_block_dangerous_cost_update();


--
-- Name: wholesale_order_items trg_product_default_unit; Type: TRIGGER; Schema: public; Owner: postgres
--

CREATE TRIGGER trg_product_default_unit AFTER INSERT ON public.wholesale_order_items FOR EACH ROW EXECUTE FUNCTION public.recompute_product_default_unit();


--
-- Name: products trg_products_price_history; Type: TRIGGER; Schema: public; Owner: postgres
--

CREATE TRIGGER trg_products_price_history AFTER UPDATE ON public.products FOR EACH ROW WHEN (((new.retail_price IS DISTINCT FROM old.retail_price) OR (new.wholesale_price IS DISTINCT FROM old.wholesale_price) OR (new.purchase_cost IS DISTINCT FROM old.purchase_cost))) EXECUTE FUNCTION public.record_price_change();


--
-- Name: products trg_products_updated_at; Type: TRIGGER; Schema: public; Owner: postgres
--

CREATE TRIGGER trg_products_updated_at BEFORE UPDATE ON public.products FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();


--
-- Name: products trg_retail_plausibility_guard; Type: TRIGGER; Schema: public; Owner: postgres
--

CREATE TRIGGER trg_retail_plausibility_guard BEFORE UPDATE OF retail_price ON public.products FOR EACH ROW WHEN (((new.retail_price IS DISTINCT FROM old.retail_price) AND (new.retail_price > 0))) EXECUTE FUNCTION public.fn_block_implausible_retail();


--
-- Name: supplier_product_mappings trg_spm_updated_at; Type: TRIGGER; Schema: public; Owner: postgres
--

CREATE TRIGGER trg_spm_updated_at BEFORE UPDATE ON public.supplier_product_mappings FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();


