--

CREATE POLICY portal_insert_order_items ON public.wholesale_order_items FOR INSERT WITH CHECK ((order_id IN ( SELECT o.id
   FROM (public.wholesale_orders o
     JOIN public.wholesale_customers c ON ((c.id = o.customer_id)))
  WHERE (c.portal_user_id = auth.uid()))));


